'use client'

import { useState } from 'react'
import { useForm } from '@tanstack/react-form'
import { SearchIcon, SearchXIcon } from 'lucide-react'
import * as z from 'zod'

import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card'
import {
  Empty,
  EmptyDescription,
  EmptyHeader,
  EmptyMedia,
  EmptyTitle,
} from '@/components/ui/empty'
import { Field, FieldError, FieldLabel } from '@/components/ui/field'
import { Input } from '@/components/ui/input'
import {
  Select,
  SelectContent,
  SelectGroup,
  SelectItem,
  SelectLabel,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'

type OrderStatus = 'paid' | 'pending' | 'refunded'

type Order = {
  id: string
  customer: string
  status: OrderStatus
  amount: number
}

const ORDERS: Order[] = [
  { id: 'INV-1001', customer: 'Acme Inc.', status: 'paid', amount: 1200 },
  { id: 'INV-1002', customer: 'Globex', status: 'pending', amount: 340 },
  { id: 'INV-1003', customer: 'Initech', status: 'refunded', amount: 90 },
  { id: 'INV-1004', customer: 'Umbrella Co.', status: 'paid', amount: 5400 },
  { id: 'INV-1005', customer: 'Hooli', status: 'pending', amount: 760 },
]

const statusVariant: Record<OrderStatus, 'default' | 'outline' | 'destructive'> =
  {
    paid: 'default',
    pending: 'outline',
    refunded: 'destructive',
  }

const filterSchema = z.object({
  query: z.string(),
  status: z.enum(['all', 'paid', 'pending', 'refunded']),
  minAmount: z
    .string()
    .refine(
      (v) => v === '' || (!Number.isNaN(Number(v)) && Number(v) >= 0),
      'Enter a non-negative number.',
    ),
})

type FilterValues = z.infer<typeof filterSchema>

function applyFilters({ query, status, minAmount }: FilterValues): Order[] {
  const q = query.trim().toLowerCase()
  const min = minAmount === '' ? 0 : Number(minAmount)
  return ORDERS.filter((order) => {
    const matchesQuery =
      q === '' ||
      order.id.toLowerCase().includes(q) ||
      order.customer.toLowerCase().includes(q)
    const matchesStatus = status === 'all' || order.status === status
    return matchesQuery && matchesStatus && order.amount >= min
  })
}

export function TsfAdvanced03() {
  const [results, setResults] = useState<Order[]>(ORDERS)

  const form = useForm({
    defaultValues: {
      query: '',
      status: 'all',
      minAmount: '',
    } as FilterValues,
    validators: { onSubmit: filterSchema },
    onSubmit: async ({ value }) => {
      setResults(applyFilters(value))
    },
  })

  return (
    <Card className="w-full max-w-2xl">
      <CardHeader>
        <CardTitle>Orders</CardTitle>
        <CardDescription>
          Filter the table below — the minimum amount is validated on search.
        </CardDescription>
      </CardHeader>
      <CardContent className="flex flex-col gap-4">
        <form
          onSubmit={(e) => {
            e.preventDefault()
            form.handleSubmit()
          }}
          className="flex flex-col gap-3 sm:flex-row sm:items-start"
        >
          <form.Field name="query">
            {(field) => (
              <Field className="sm:flex-1">
                <FieldLabel htmlFor={field.name}>Search</FieldLabel>
                <Input
                  id={field.name}
                  name={field.name}
                  placeholder="Invoice or customer"
                  value={field.state.value}
                  onBlur={field.handleBlur}
                  onChange={(e) => field.handleChange(e.target.value)}
                />
              </Field>
            )}
          </form.Field>
          <form.Field name="status">
            {(field) => (
              <Field className="sm:w-36">
                <FieldLabel htmlFor={field.name}>Status</FieldLabel>
                <Select
                  value={field.state.value}
                  onValueChange={(v) =>
                    field.handleChange(v as FilterValues['status'])
                  }
                >
                  <SelectTrigger id={field.name} className="w-full">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectGroup>
                      <SelectLabel>Status</SelectLabel>
                      <SelectItem value="all">All</SelectItem>
                      <SelectItem value="paid">Paid</SelectItem>
                      <SelectItem value="pending">Pending</SelectItem>
                      <SelectItem value="refunded">Refunded</SelectItem>
                    </SelectGroup>
                  </SelectContent>
                </Select>
              </Field>
            )}
          </form.Field>
          <form.Field name="minAmount">
            {(field) => {
              const isInvalid =
                field.state.meta.isTouched && !field.state.meta.isValid
              return (
                <Field className="sm:w-28" data-invalid={isInvalid}>
                  <FieldLabel htmlFor={field.name}>Min $</FieldLabel>
                  <Input
                    id={field.name}
                    name={field.name}
                    inputMode="decimal"
                    placeholder="0"
                    aria-invalid={isInvalid}
                    value={field.state.value}
                    onBlur={field.handleBlur}
                    onChange={(e) => field.handleChange(e.target.value)}
                  />
                  {isInvalid && <FieldError errors={field.state.meta.errors} />}
                </Field>
              )
            }}
          </form.Field>
          <Button type="submit" size="sm" className="sm:mt-6">
            <SearchIcon className="size-4" />
            Search
          </Button>
        </form>

        {results.length === 0 ? (
          <Empty className="border">
            <EmptyHeader>
              <EmptyMedia variant="icon">
                <SearchXIcon />
              </EmptyMedia>
              <EmptyTitle>No matching orders</EmptyTitle>
              <EmptyDescription>
                Try lowering the minimum or clearing the search.
              </EmptyDescription>
            </EmptyHeader>
          </Empty>
        ) : (
          <div className="rounded-lg border">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Invoice</TableHead>
                  <TableHead>Customer</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead className="text-right">Amount</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {results.map((order) => (
                  <TableRow key={order.id}>
                    <TableCell className="font-medium">{order.id}</TableCell>
                    <TableCell>{order.customer}</TableCell>
                    <TableCell>
                      <Badge
                        variant={statusVariant[order.status]}
                        className="capitalize"
                      >
                        {order.status}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-right tabular-nums">
                      ${order.amount.toLocaleString()}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
        )}
        <p className="text-muted-foreground text-sm">
          {results.length} of {ORDERS.length} orders
        </p>
      </CardContent>
    </Card>
  )
}
